configuration.jsScript:
var html = msg;
var priceMatch = html.match(/[\$¥€£]\s*([\d,]+\.?\d*)/)
  || html.match(/price["']?\s*[:=]\s*["']?([\d,]+\.?\d*)/);
var result = {
  product_url: metadata.url || '',
  current_price: priceMatch ? parseFloat(priceMatch[1].replace(/,/g, '')) : null,
  currency: html.match(/[\$¥€£]/) ? html.match(/[\$¥€£]/)[0] : 'USD',
  scraped_at: new Date().toISOString(),
  previous_price: metadata.previous_price ? parseFloat(metadata.previous_price) : null
};
if (result.current_price && result.previous_price) {
  result.price_changed = result.current_price !== result.previous_price;
  result.price_diff = result.current_price - result.previous_price;
  result.price_diff_pct = ((result.price_diff / result.previous_price) * 100).toFixed(2);
} else {
  result.price_changed = false;
}
msg = JSON.stringify(result);
return {'msg': msg, 'metadata': metadata, 'msgType': msgType};

configuration.body:
Price change detected!

Product: ${url}
Previous price: ${previous_price}
Current price: ${current_price}
Change: ${price_diff_pct}%

Scraped at: ${scraped_at}
